#include <bits/stdc++.h>
using namespace std;
const int N=5e5+5,INF=5e8;
struct Node{
    int ans,p,q,mxa,mnb;
    Node():ans(-INF),p(-INF),q(-INF),mxa(-INF),mnb(INF){}
}t[4*N];
int n,m,a[N],b[N];
void Build(int cur,int l,int r){
	if(l==r)
		t[cur].mxa=a[l],t[cur].mnb=b[l];
	else{
		int mid=(l+r)/2;
		Build(cur*2,l,mid);
		Build(cur*2+1,mid+1,r);
		t[cur].mxa=max(t[cur*2].mxa,t[cur*2+1].mxa);
		t[cur].mnb=min(t[cur*2].mnb,t[cur*2+1].mnb);
		t[cur].p=max(max(t[cur*2].p,t[cur*2+1].p),t[cur*2].mxa-t[cur*2+1].mnb);
		t[cur].q=max(max(t[cur*2].q,t[cur*2+1].q),t[cur*2+1].mxa-t[cur*2].mnb);
		t[cur].ans=max(max(t[cur*2].ans,t[cur*2+1].ans),max(t[cur*2].p+t[cur*2+1].mxa,t[cur*2].mxa+t[cur*2+1].q));
	}
}
void Modify(int cur,int l,int r,int x,int y,int k){
	if(l==r && l==x)
		if(k==1)
			a[x]=y,t[cur].mxa=a[l],t[cur].mnb=b[l];
		else
			b[x]=y,t[cur].mxa=a[l],t[cur].mnb=b[l];
	else{
		int mid=(l+r)/2;
		if(x>mid)
			Modify(cur*2+1,mid+1,r,x,y,k);
		else
			Modify(cur*2,l,mid,x,y,k);
		t[cur].mxa=max(t[cur*2].mxa,t[cur*2+1].mxa);
		t[cur].mnb=min(t[cur*2].mnb,t[cur*2+1].mnb);
		t[cur].p=max(max(t[cur*2].p,t[cur*2+1].p),t[cur*2].mxa-t[cur*2+1].mnb);
		t[cur].q=max(max(t[cur*2].q,t[cur*2+1].q),t[cur*2+1].mxa-t[cur*2].mnb);
		t[cur].ans=max(max(t[cur*2].ans,t[cur*2+1].ans),max(t[cur*2].p+t[cur*2+1].mxa,t[cur*2].mxa+t[cur*2+1].q));
	}
}
Node Find(int cur,int l,int r,int x,int y){
	if(l>=x && r<=y)
		return t[cur];
	else{
		int mid=(l+r)/2;
		Node u,v,re;
		if(x>mid){
			v=Find(cur*2+1,mid+1,r,x,y);
			return v;
		}
		if(y<=mid){
			u=Find(cur*2,l,mid,x,y);
			return u;
		}
		v=Find(cur*2+1,mid+1,r,x,y);
		u=Find(cur*2,l,mid,x,y);
		re.mxa=max(u.mxa,v.mxa);
		re.mnb=min(u.mnb,v.mnb);
		re.p=max(max(u.p,v.p),u.mxa-v.mnb);
		re.q=max(max(u.q,v.q),v.mxa-u.mnb);
		re.ans=max(max(u.ans,v.ans),max(u.p+v.mxa,u.mxa+v.q));
		return re;
	}
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        cin>>a[i];
    for(int i=1;i<=n;i++)
        cin>>b[i];
    Build(1,1,n); 
    while(m--){
    	int k,x,y;
    	cin>>k>>x>>y;
    	if(k<3)
    		Modify(1,1,n,x,y,k);
		else
			cout<<Find(1,1,n,x,y).ans<<'\n';
	}
    return 0;
}
